select_Dv() { DVS=$(set | grep -E '^Dv[0-9]+=' | sed 's/=.*//' | sort -V); COUNT_dv=$(echo "$DVS" | wc -l); echo; echo -en "${YELLOW}–í–≤–Ķ–ī–ł—ā–Ķ –≤–Ķ—Ä—Ā–ł—é —Ā—ā—Ä–į—ā–Ķ–≥–ł–ł –ī–Ľ—Ź discord.media ${NC}(1-$COUNT_dv)${YELLOW}:${NC} "; read CHOICE_DV </dev/tty
case "$CHOICE_DV" in ''|*[!0-9]*|0) return 1;; esac; SELECTED_dv="Dv$CHOICE_DV"; echo "$DVS" | grep -qx "$SELECTED_dv" || return 1; NEW_NUM="$CHOICE_DV"; NEW_STRAT=$(eval echo \"\$$SELECTED_dv\"); }
switch_Dv() { select_Dv || return 1; grep -q -E '^[[:space:]]*--filter-tcp=2053,2083,2087,2096,8443' "$CONF" || { echo -e "\n${RED}–°—ā—Ä–į—ā–Ķ–≥–ł—Ź –Ĺ–Ķ –Ņ–ĺ–ī—Ö–ĺ–ī–ł—ā!${NC}\n"; PAUSE; return 1; }; START=$(grep -n -E '^[[:space:]]*--filter-tcp=2053,2083,2087,2096,8443' "$CONF" | cut -d: -f1)
END=$(tail -n +"$START" "$CONF" | grep -n -m1 -E '^--new$|^'\''$' | cut -d: -f1); END=$((START + END - 1)); sed -i "${START},$((END-1))d" "$CONF"; LINE=$START; echo "$NEW_STRAT" | while IFS= read -r l; do sed -i "${LINE}i$l" "$CONF"; LINE=$((LINE + 1)); done
if grep -q -E '^#[[:space:]]*Dv' "$CONF"; then sed -i "s/^#[[:space:]]*Dv[0-9]\+/#Dv$NEW_NUM/" "$CONF"; else sed -i "$START i#Dv$NEW_NUM" "$CONF"; fi; echo -e "\n${MAGENTA}–ú–Ķ–Ĺ—Ź–Ķ–ľ —Ā—ā—Ä–į—ā–Ķ–≥–ł—é –ī–Ľ—Ź discord.media${NC}"; ZAPRET_RESTART; echo -e "${GREEN}–°—ā—Ä–į—ā–Ķ–≥–ł—Ź ${NC}Dv$NEW_NUM${GREEN} –Ņ—Ä–ł–ľ–Ķ–Ĺ–Ķ–Ĺ–į!${NC}\n"; PAUSE; }
toggle_finland_hosts() { if grep -q "$Fin_IP_Dis" /etc/hosts; then sed -i "/$Fin_IP_Dis/d" /etc/hosts; echo -e "\n${MAGENTA}–£–ī–į–Ľ—Ź–Ķ–ľ –§–ł–Ĺ—Ā–ļ–ł–Ķ IP${NC}"; /etc/init.d/dnsmasq restart 2>/dev/null
echo -e "${GREEN}–§–ł–Ĺ—Ā–ļ–ł–Ķ ${NC}IP${GREEN} —É–ī–į–Ľ–Ķ–Ĺ—č${NC}\n"; else seq 10000 10199 | awk '{print "104.25.158.178 finland"$1".discord.media"}' | grep -vxFf /etc/hosts >> /etc/hosts; echo -e "\n${MAGENTA}–Ē–ĺ–Ī–į–≤–Ľ—Ź–Ķ–ľ –§–ł–Ĺ—Ā–ļ–ł–Ķ IP${NC}"; /etc/init.d/dnsmasq restart 2>/dev/null
echo -e "${GREEN}–§–ł–Ĺ—Ā–ļ–ł–Ķ ${NC}IP${GREEN} –ī–ĺ–Ī–į–≤–Ľ–Ķ–Ĺ—č${NC}\n"; fi; PAUSE; }
