$output_shown && echo; if [ "$NO_PAUSE" = "1" ]; then SELECTED="50-stun4all"; URL="https://raw.githubusercontent.com/bol-van/zapret/master/init.d/custom.d.examples.linux/50-stun4all"; else
echo -e "${CYAN}1) ${GREEN}–£—Ā—ā–į–Ĺ–ĺ–≤–ł—ā—Ć —Ā–ļ—Ä–ł–Ņ—ā ${NC}50-stun4all\n${CYAN}2) ${GREEN}–£—Ā—ā–į–Ĺ–ĺ–≤–ł—ā—Ć —Ā–ļ—Ä–ł–Ņ—ā ${NC}50-quic4all\n${CYAN}3) ${GREEN}–£—Ā—ā–į–Ĺ–ĺ–≤–ł—ā—Ć —Ā–ļ—Ä–ł–Ņ—ā ${NC}50-discord-media\n${CYAN}4) ${GREEN}–£—Ā—ā–į–Ĺ–ĺ–≤–ł—ā—Ć —Ā–ļ—Ä–ł–Ņ—ā ${NC}50-discord\n${CYAN}5) ${GREEN}–£–ī–į–Ľ–ł—ā—Ć —Ā–ļ—Ä–ł–Ņ—ā${NC}"
