echo -ne "${CYAN}6) $FIN_TXT\n${CYAN}7) ${GREEN}–í—č–Ī—Ä–į—ā—Ć –ł —É—Ā—ā–į–Ĺ–ĺ–≤–ł—ā—Ć —Ā—ā—Ä–į—ā–Ķ–≥–ł—é –ī–Ľ—Ź ${NC}discord.media\n${CYAN}Enter) ${GREEN}–í—č—Ö–ĺ–ī –≤ –≥–Ľ–į–≤–Ĺ–ĺ–Ķ –ľ–Ķ–Ĺ—é${NC}\n\n${YELLOW}–í—č–Ī–Ķ—Ä–ł—ā–Ķ –Ņ—É–Ĺ–ļ—ā:${NC} " && read choiceSC; case "$choiceSC" in
1) SELECTED="50-stun4all"; URL="https://raw.githubusercontent.com/bol-van/zapret/master/init.d/custom.d.examples.linux/50-stun4all";; 2) SELECTED="50-quic4all"; URL="https://raw.githubusercontent.com/bol-van/zapret/master/init.d/custom.d.examples.linux/50-quic4all";;
3) SELECTED="50-discord-media"; URL="https://raw.githubusercontent.com/bol-van/zapret/master/init.d/custom.d.examples.linux/50-discord-media";; 4) SELECTED="50-discord"; URL="https://raw.githubusercontent.com/bol-van/zapret/v70.5/init.d/custom.d.examples.linux/50-discord";;
5) [ ! -f /etc/init.d/zapret ] && { echo -e "\n${RED}Zapret –Ĺ–Ķ —É—Ā—ā–į–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ!${NC}\n"; PAUSE; continue; }; echo -e "\n${MAGENTA}–£–ī–į–Ľ—Ź–Ķ–ľ —Ā–ļ—Ä–ł–Ņ—ā${NC}"; rm -f "$CUSTOM_DIR/50-script.sh" 2>/dev/null; sed -i "/DISABLE_CUSTOM/s/'0'/'1'/" /etc/config/zapret; ZAPRET_RESTART; echo -e "${GREEN}–°–ļ—Ä–ł–Ņ—ā —É–ī–į–Ľ—Ď–Ĺ!${NC}\n"; PAUSE; continue;;
6) toggle_finland_hosts; continue;; 7) switch_Dv; continue;; *) return;; esac; fi; [ ! -f /etc/init.d/zapret ] && { echo -e "\n${RED}Zapret –Ĺ–Ķ —É—Ā—ā–į–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ!${NC}\n"; PAUSE; continue; }
if wget -q -U "Mozilla/5.0" -O "$CUSTOM_DIR/50-script.sh" "$URL"; then [ "$NO_PAUSE" != "1" ] && echo; echo -e "${MAGENTA}–£—Ā—ā–į–Ĺ–į–≤–Ľ–ł–≤–į–Ķ–ľ —Ā–ļ—Ä–ł–Ņ—ā${NC}\n${GREEN}–°–ļ—Ä–ł–Ņ—ā ${NC}$SELECTED${GREEN} —É—Ā–Ņ–Ķ—ą–Ĺ–ĺ —É—Ā—ā–į–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ!${NC}\n"; else echo -e "\n${RED}–ě—ą–ł–Ī–ļ–į –Ņ—Ä–ł —Ā–ļ–į—á–ł–≤–į–Ĺ–ł–ł —Ā–ļ—Ä–ł–Ņ—ā–į!${NC}\n"; PAUSE; continue; fi
