remove_ports_if_present() { local OPTION="$1"; local PORTS="$2"; for p in $(echo "$PORTS" | tr ',' ' '); do sed -i "\#option $OPTION '#s#,$p##g" "$CONF"; done; sed -i "\#option $OPTION '#s#,,#,#g; s#,\$##" "$CONF"; }
add_ports_if_missing() { local OPTION="$1"; local PORTS="$2"; for p in $(echo "$PORTS" | tr ',' ' '); do grep -q "option $OPTION '.*\b$p\b" "$CONF" || sed -i "\#option $OPTION '#s#'\$#,$p'#" "$CONF"; done; }
strategy_TCP_common() { printf "%s\n" "--new" "--filter-tcp=$PORTS_TCP" "--dpi-desync-any-protocol=1" "--dpi-desync-cutoff=n5" "--dpi-desync=multisplit" "--dpi-desync-split-seqovl=582" "--dpi-desync-split-pos=1" "--dpi-desync-split-seqovl-pattern=/opt/zapret/files/fake/stun.bin"; }
strategy_Gv1() { printf "%s\n" "#Gv1" "--new" "--filter-udp=$PORTS_UDP" "--dpi-desync=fake" "--dpi-desync-cutoff=d2" "--dpi-desync-any-protocol=1" "--dpi-desync-fake-unknown-udp=/opt/zapret/files/fake/stun.bin"; }
strategy_Gv() { local N="$1"; printf "%s\n" "#Gv$N" "--new" "--filter-udp=$PORTS_UDP" "--dpi-desync=fake" "--dpi-desync-repeats=10" "--dpi-desync-any-protocol=1" "--dpi-desync-fake-unknown-udp=/opt/zapret/files/fake/quic_initial_www_google_com.bin" "--dpi-desync-cutoff=n$N"; }
fix_GAME() { local NO_PAUSE=$1; [ ! -f /etc/init.d/zapret ] && { echo -e "\n${RED}Zapret –Ĺ–Ķ —É—Ā—ā–į–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ!${NC}\n"; PAUSE; return; }; local CURRENT_GAME=""; for i in 1 2 3 4; do grep -q "^#Gv$i" "$CONF" && CURRENT_GAME="Gv$i"; done
if [ -n "$NO_PAUSE" ]; then GAME_CHOICE="$NO_PAUSE"; else echo -e "\n${MAGENTA}–í—č–Ī–Ķ—Ä–ł—ā–Ķ —Ā—ā—Ä–į—ā–Ķ–≥–ł—é –ī–Ľ—Ź –ł–≥—Ä${NC}"; for i in $(seq 1 4); do if [ "$CURRENT_GAME" = "Gv$i" ]; then echo -e "${CYAN}$i) ${GREEN}–£–ī–į–Ľ–ł—ā—Ć ${NC}Gv$i"; else echo -e "${CYAN}$i) ${GREEN}–£—Ā—ā–į–Ĺ–ĺ–≤–ł—ā—Ć ${NC}Gv$i"; fi; done
echo -e "${CYAN}Enter) ${GREEN}–í—č—Ö–ĺ–ī –≤ –ľ–Ķ–Ĺ—é —Ā—ā—Ä–į—ā–Ķ–≥–ł–Ļ"; echo -en "\n${YELLOW}–í—č–Ī–Ķ—Ä–ł—ā–Ķ –Ņ—É–Ĺ–ļ—ā: ${NC}"; read GAME_CHOICE; fi; case "$GAME_CHOICE" in 1|2|3|4) ;; *) return ;; esac; LAST_QUOTE=$(grep -n "^'\$" "$CONF" | tail -n1 | cut -d: -f1)
if grep -q "^#Gv" "$CONF"; then Gv_LINE=$(grep -n "^#Gv" "$CONF" | tail -n1 | cut -d: -f1); sed -i "${Gv_LINE},${LAST_QUOTE}d" "$CONF"; elif [ -n "$LAST_QUOTE" ]; then sed -i "${LAST_QUOTE},\$d" "$CONF"; fi
if [ "$CURRENT_GAME" = "Gv$GAME_CHOICE" ]; then remove_ports_if_present NFQWS_PORTS_UDP "$PORTS_UDP"; remove_ports_if_present NFQWS_PORTS_TCP "$PORTS_TCP"; echo "'" >> "$CONF"; echo -e "\n${CYAN}–£–ī–į–Ľ—Ź–Ķ–ľ —Ā—ā—Ä–į—ā–Ķ–≥–ł—é –ī–Ľ—Ź –ł–≥—Ä ${NC}"; ZAPRET_RESTART
echo -e "${GREEN}–°—ā—Ä–į—ā–Ķ–≥–ł—Ź –ī–Ľ—Ź –ł–≥—Ä —É–ī–į–Ľ–Ķ–Ĺ–į!${NC}\n"; [ -z "$NO_PAUSE" ] && PAUSE; return; fi; if [ "$GAME_CHOICE" -eq 1 ]; then STRATEGY="$(strategy_Gv1; strategy_TCP_common)"; else STRATEGY="$(strategy_Gv "$GAME_CHOICE"; strategy_TCP_common)"; fi
echo "$STRATEGY" | sed '/^$/d' >> "$CONF"; echo "'" >> "$CONF"; add_ports_if_missing NFQWS_PORTS_UDP "$PORTS_UDP"; add_ports_if_missing NFQWS_PORTS_TCP "$PORTS_TCP"
[ -z "$NO_PAUSE" ] && echo; echo -e "${CYAN}–£—Ā—ā–į–Ĺ–į–≤–Ľ–ł–≤–į–Ķ–ľ —Ā—ā—Ä–į—ā–Ķ–≥–ł—é –ī–Ľ—Ź –ł–≥—Ä ${NC}"; ZAPRET_RESTART; echo -e "${GREEN}–°—ā—Ä–į—ā–Ķ–≥–ł—Ź –ī–Ľ—Ź –ł–≥—Ä ${NC}Gv$GAME_CHOICE${GREEN} —É—Ā—ā–į–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ–į!${NC}\n"; [ -z "$NO_PAUSE" ] && PAUSE; }
