[ ! -f /etc/init.d/zapret ] && { echo -e "${RED}Zapret –Ĺ–Ķ —É—Ā—ā–į–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ!${NC}\n"; PAUSE; return; }; install_strategy $STR_VERSION_AUTOINSTALL "1"; echo -e "\n${MAGENTA}–†–Ķ–ī–į–ļ—ā–ł—Ä—É–Ķ–ľ hosts${NC}\n${CYAN}–Ē–ĺ–Ī–į–≤–Ľ—Ź–Ķ–ľ –ī–ĺ–ľ–Ķ–Ĺ—č –≤${NC} hosts"
