echo -e "${MAGENTA}–£—Ā—ā–į–Ĺ–į–≤–Ľ–ł–≤–į–Ķ–ľ —Ā—ā—Ä–į—ā–Ķ–≥–ł—é ${version}${NC}\n${CYAN}–ú–Ķ–Ĺ—Ź–Ķ–ľ —Ā—ā—Ä–į—ā–Ķ–≥–ł—é${NC}"; sed -i "/^[[:space:]]*option NFQWS_OPT '/,\$d" "$CONF"; { echo "  option NFQWS_OPT '"; strategy_"$version"; echo "'"; } >> "$CONF"
