echo -e "${CYAN}–Ē–ĺ–Ī–į–≤–Ľ—Ź–Ķ–ľ –ī–ĺ–ľ–Ķ–Ĺ—č –≤ –ł—Ā–ļ–Ľ—é—á–Ķ–Ĺ–ł—Ź${NC}"; rm -f "$EXCLUDE_FILE"; wget -q -U "Mozilla/5.0" -O "$EXCLUDE_FILE" "$EXCLUDE_URL" || { echo -e "\n${RED}–Ě–Ķ —É–ī–į–Ľ–ĺ—Ā—Ć –∑–į–≥—Ä—É–∑–ł—ā—Ć exclude —Ą–į–Ļ–Ľ${NC}\n"; PAUSE; return; }
discord_str_add; echo -e "${CYAN}–ü—Ä–ł–ľ–Ķ–Ĺ—Ź–Ķ–ľ –Ĺ–ĺ–≤—É—é —Ā—ā—Ä–į—ā–Ķ–≥–ł—é –ł –Ĺ–į—Ā—ā—Ä–ĺ–Ļ–ļ–ł${NC}"; ZAPRET_RESTART; echo -e "${GREEN}–°—ā—Ä–į—ā–Ķ–≥–ł—Ź ${NC}${version}${GREEN} —É—Ā—ā–į–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ–į!${NC}"
grep -Fq "=ts" "$CONF" && echo -e "\n${YELLOW}–Ē–Ľ—Ź —Ä–į–Ī–ĺ—ā—č —ć—ā–ĺ–Ļ —Ā—ā—Ä–į—ā–Ķ–≥–ł–ł, –≤ —ā–Ķ—Ä–ľ–ł–Ĺ–į–Ľ–Ķ Windows –Ĺ—É–∂–Ĺ–ĺ –≤—č–Ņ–ĺ–Ľ–Ĺ–ł—ā—Ć:${NC}\nnetsh int tcp set global timestamps=enabled"; [ "$NO_PAUSE" != "1" ] && echo && PAUSE; }
