DoH_menu() { while true; do get_doh_status; clear; echo -e "${MAGENTA}–ú–Ķ–Ĺ—é DNS over HTTPS${NC}\n"; if [ "$PKG_IS_APK" -eq 1 ]; then apk info -e https-dns-proxy >/dev/null 2>&1 && doh_st="–£–ī–į–Ľ–ł—ā—Ć" || doh_st="–£—Ā—ā–į–Ĺ–ĺ–≤–ł—ā—Ć"; else
opkg list-installed | grep -q '^https-dns-proxy ' && doh_st="–£–ī–į–Ľ–ł—ā—Ć" || doh_st="–£—Ā—ā–į–Ĺ–ĺ–≤–ł—ā—Ć"; fi; if [ -n "$DOH_STATUS" ]; then if [ "$PKG_IS_APK" -eq 1 ]; then apk info -e https-dns-proxy >/dev/null 2>&1 && echo -e "${YELLOW}DNS over HTTPS: ${NC}$DOH_STATUS\n"
else opkg list-installed | grep -q '^https-dns-proxy ' && echo -e "${YELLOW}DNS over HTTPS: ${NC}$DOH_STATUS\n"; fi; fi
echo -e "${CYAN}1)${GREEN} $doh_st ${NC}DNS over HTTPS\n${CYAN}2)${GREEN} –Ě–į—Ā—ā—Ä–ĺ–ł—ā—Ć ${NC}Comss DNS\n${CYAN}3)${GREEN} –Ě–į—Ā—ā—Ä–ĺ–ł—ā—Ć ${NC}Xbox DNS\n${CYAN}4)${GREEN} –Ě–į—Ā—ā—Ä–ĺ–ł—ā—Ć ${NC}dns.malw.link"
echo -e "${CYAN}5)${GREEN} –Ě–į—Ā—ā—Ä–ĺ–ł—ā—Ć ${NC}dns.malw.link (CloudFlare)\n${CYAN}6)${GREEN} –Ě–į—Ā—ā—Ä–ĺ–ł—ā—Ć ${NC}dns.mafioznik.xyz\n${CYAN}7)${GREEN} –Ě–į—Ā—ā—Ä–ĺ–ł—ā—Ć ${NC}dns.astracat.ru\n${CYAN}0)${GREEN} –í–Ķ—Ä–Ĺ—É—ā—Ć ${NC}–Ĺ–į—Ā—ā—Ä–ĺ–Ļ–ļ–ł –Ņ–ĺ —É–ľ–ĺ–Ľ—á–į–Ĺ–ł—é"
echo -ne "${CYAN}Enter) ${GREEN}–í—č—Ö–ĺ–ī –≤ –≥–Ľ–į–≤–Ĺ–ĺ–Ķ –ľ–Ķ–Ĺ—é${NC}\n\n${YELLOW}–í—č–Ī–Ķ—Ä–ł—ā–Ķ –Ņ—É–Ĺ–ļ—ā:${NC} "; read -r choiceDOH; [ -z "$choiceDOH" ] && return; case "$choiceDOH" in 1) D_o_H;; 2) doh_install && setup_doh "$doh_comss" "Comss.one DNS";;
3) doh_install && setup_doh "$doh_xbox" "Xbox DNS";; 4) doh_install && setup_doh "$doh_query" "dns.malw.link";; 5) doh_install && setup_doh "$doh_queryCF" "dns.malw.link (CloudFlare)";;
6) doh_install && setup_doh "$doh_mafioznik" "dns.mafioznik.xyz";; 7) doh_install && setup_doh "$doh_astracat" "dns.astracat.ru";; 0) doh_install && setup_doh "$doh_def" "–Ĺ–į—Ā—ā—Ä–ĺ–Ļ–ļ–ł –Ņ–ĺ —É–ľ–ĺ–Ľ—á–į–Ĺ–ł—é";; *) return;; esac; done; }
setup_doh() { local config="$1"; local name="$2"; echo -e "\n${MAGENTA}–Ě–į—Ā—ā—Ä–į–ł–≤–į–Ķ–ľ DNS over HTTPS${NC}\n${CYAN}–Ě–į—Ā—ā—Ä–į–ł–≤–į–Ķ–ľ ${NC}$name\n${CYAN}–ü—Ä–ł–ľ–Ķ–Ĺ—Ź–Ķ–ľ –Ĺ–ĺ–≤—č–Ķ –Ĺ–į—Ā—ā—Ä–ĺ–Ļ–ļ–ł${NC}"
rm -f "$fileDoH"; printf '%s\n' "$doh_set" "$config" > "$fileDoH"; /etc/init.d/https-dns-proxy reload >/dev/null 2>&1; /etc/init.d/https-dns-proxy restart >/dev/null 2>&1; echo -e "DNS over HTTP ${GREEN}–Ĺ–į—Ā—ā—Ä–ĺ–Ķ–Ĺ!${NC}\n"; PAUSE; }
get_doh_status() { DOH_STATUS=""; [ ! -f "$fileDoH" ] && return; if grep -q "dns.comss.one" "$fileDoH"; then DOH_STATUS="Comss DNS"; elif grep -q "xbox-dns.ru" "$fileDoH"; then DOH_STATUS="Xbox DNS"; elif grep -q "5u35p8m9i7.cloudflare-gateway.com" "$fileDoH"
then DOH_STATUS="dns.malw.link (CloudFlare)"; elif grep -q "dns.malw.link" "$fileDoH"; then DOH_STATUS="dns.malw.link"; elif grep -q "dns.mafioznik.xyz" "$fileDoH"; then DOH_STATUS="dns.mafioznik.xyz"; elif grep -q "dns.astracat.ru" "$fileDoH"; then DOH_STATUS="dns.astracat.ru"; else DOH_STATUS="—É—Ā—ā–į–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ"; fi; }
D_o_H() { if [ "$PKG_IS_APK" -eq 1 ]; then PKG_CHECK="https-dns-proxy"; PKG_MANAGER="apk"; else PKG_CHECK="https-dns-proxy"; PKG_MANAGER="opkg"; fi; if { [ "$PKG_MANAGER" = "apk" ] && apk info -e "$PKG_CHECK" >/dev/null 2>&1; } || { [ "$PKG_MANAGER" = "opkg" ] && opkg list-installed | grep -q '^https-dns-proxy '; }; then
echo -e "\n${MAGENTA}–£–ī–į–Ľ—Ź–Ķ–ľ DNS over HTTPS${NC}\n${CYAN}–£–ī–į–Ľ—Ź–Ķ–ľ –Ņ–į–ļ–Ķ—ā—č${NC}"; if [ "$PKG_MANAGER" = "apk" ]; then apk del https-dns-proxy luci-app-https-dns-proxy >/dev/null 2>&1; else opkg --force-removal-of-dependent-packages --autoremove remove https-dns-proxy luci-app-https-dns-proxy >/dev/null 2>&1; fi
echo -e "${CYAN}–£–ī–į–Ľ—Ź–Ķ–ľ —Ą–į–Ļ–Ľ—č –ļ–ĺ–Ĺ—Ą–ł–≥—É—Ä–į—Ü–ł–ł${NC}"; rm -f /etc/config/https-dns-proxy /etc/init.d/https-dns-proxy; echo -e "DNS over HTTPS${GREEN} —É–ī–į–Ľ—Ď–Ĺ!${NC}\n"; PAUSE; else echo -e "\n${MAGENTA}–£—Ā—ā–į–Ĺ–į–≤–Ľ–ł–≤–į–Ķ–ľ DNS over HTTPS${NC}\n${CYAN}–ě–Ī–Ĺ–ĺ–≤–Ľ—Ź–Ķ–ľ —Ā–Ņ–ł—Ā–ĺ–ļ –Ņ–į–ļ–Ķ—ā–ĺ–≤${NC}"
$UPDATE >/dev/null 2>&1 || { echo -e "\n${RED}–ě—ą–ł–Ī–ļ–į –Ņ—Ä–ł –ĺ–Ī–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ–ł–ł —Ā–Ņ–ł—Ā–ļ–į –Ņ–į–ļ–Ķ—ā–ĺ–≤!${NC}\n"; PAUSE; return; }
echo -e "${CYAN}–£—Ā—ā–į–Ĺ–į–≤–Ľ–ł–≤–į–Ķ–ľ ${NC}https-dns-proxy"; if [ "$PKG_MANAGER" = "apk" ]; then apk add https-dns-proxy >/dev/null 2>&1 || { echo -e "\n${RED}–ě—ą–ł–Ī–ļ–į –Ņ—Ä–ł —É—Ā—ā–į–Ĺ–ĺ–≤–ļ–Ķ!${NC}\n"; PAUSE; return; }; else opkg install https-dns-proxy >/dev/null 2>&1 || { echo -e "\n${RED}–ě—ą–ł–Ī–ļ–į –Ņ—Ä–ł —É—Ā—ā–į–Ĺ–ĺ–≤–ļ–Ķ!${NC}\n"; PAUSE; return; }; fi
echo -e "${CYAN}–£—Ā—ā–į–Ĺ–į–≤–Ľ–ł–≤–į–Ķ–ľ ${NC}luci-app-https-dns-proxy"; if [ "$PKG_MANAGER" = "apk" ]; then apk add luci-app-https-dns-proxy >/dev/null 2>&1 || { echo -e "\n${RED}–ě—ą–ł–Ī–ļ–į –Ņ—Ä–ł —É—Ā—ā–į–Ĺ–ĺ–≤–ļ–Ķ!${NC}\n"; PAUSE; return; }; else opkg install luci-app-https-dns-proxy >/dev/null 2>&1 || { echo -e "\n${RED}–ě—ą–ł–Ī–ļ–į –Ņ—Ä–ł —É—Ā—ā–į–Ĺ–ĺ–≤–ļ–Ķ!${NC}\n"; PAUSE; return; }; fi
echo -e "DNS over HTTPS${GREEN} —É—Ā—ā–į–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ!${NC}\n"; PAUSE; fi; }
doh_install() { [ -f "$fileDoH" ] && return 0; echo -e "\n${RED}DNS over HTTPS –Ĺ–Ķ —É—Ā—ā–į–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ!${NC}\n"; PAUSE; return 1; }
doh_set=$(printf "%s\n" "config main 'config'" "	option canary_domains_icloud '1'" "	option canary_domains_mozilla '1'" "	option dnsmasq_config_update '*'" "	option force_dns '1'" "	list force_dns_port '53'" "	list force_dns_port '853'" \
"	list force_dns_src_interface 'lan'" "	option procd_trigger_wan6 '0'" "	option heartbeat_domain 'heartbeat.melmac.ca'" "	option heartbeat_sleep_timeout '10'" "	option heartbeat_wait_timeout '10'" "	option user 'nobody'" "	option group 'nogroup'" "	option listen_addr '127.0.0.1'")
doh_def=$(printf "%s\n" "" "config https-dns-proxy" "	option bootstrap_dns '1.1.1.1,1.0.0.1'" "	option resolver_url 'https://cloudflare-dns.com/dns-query'" "	option listen_port '5053'" "" "config https-dns-proxy" "	option bootstrap_dns '8.8.8.8,8.8.4.4'" "	option resolver_url 'https://dns.google/dns-query'" "	option listen_port '5054'")
doh_comss=$(printf "%s\n" "" "config https-dns-proxy" "	option resolver_url 'https://dns.comss.one/dns-query'"); doh_xbox=$(printf "%s\n" "" "config https-dns-proxy" "	option resolver_url 'https://xbox-dns.ru/dns-query'")
doh_query=$(printf "%s\n" "" "config https-dns-proxy" "	option resolver_url 'https://dns.malw.link/dns-query'"); doh_queryCF=$(printf "%s\n" "" "config https-dns-proxy" "	option resolver_url 'https://5u35p8m9i7.cloudflare-gateway.com/dns-query'")
doh_mafioznik=$(printf "%s\n" "" "config https-dns-proxy" "	option resolver_url 'https://dns.mafioznik.xyz/dns-query'"); doh_astracat=$(printf "%s\n" "" "config https-dns-proxy" "	option resolver_url 'https://dns.astracat.ru/dns-query'")
