rm -f /etc/config/ttyd; echo -e "${GREEN}–Ē–ĺ—Ā—ā—É–Ņ —É–ī–į–Ľ—Ď–Ĺ!${NC}\n"; PAUSE; else echo -e "\n${MAGENTA}–ź–ļ—ā–ł–≤–ł—Ä—É–Ķ–ľ –ī–ĺ—Ā—ā—É–Ņ –ł–∑ –Ī—Ä–į—É–∑–Ķ—Ä–į${NC}"; echo -e "${CYAN}–ě–Ī–Ĺ–ĺ–≤–Ľ—Ź–Ķ–ľ —Ā–Ņ–ł—Ā–ĺ–ļ –Ņ–į–ļ–Ķ—ā–ĺ–≤${NC}"; $UPDATE >/dev/null 2>&1 || { echo -e "\n${RED}–ě—ą–ł–Ī–ļ–į –Ņ—Ä–ł –ĺ–Ī–Ĺ–ĺ–≤–Ľ–Ķ–Ĺ–ł–ł —Ā–Ņ–ł—Ā–ļ–į –Ņ–į–ļ–Ķ—ā–ĺ–≤!${NC}\n"; PAUSE; return; }
echo -e "${CYAN}–£—Ā—ā–į–Ĺ–į–≤–Ľ–ł–≤–į–Ķ–ľ ${NC}ttyd"; if [ "$PKG_IS_APK" -eq 1 ]; then if ! apk add luci-app-ttyd >/dev/null 2>&1; then echo -e "\n${RED}–ě—ą–ł–Ī–ļ–į –Ņ—Ä–ł —É—Ā—ā–į–Ĺ–ĺ–≤–ļ–Ķ ttyd!${NC}\n"; PAUSE; return; fi; else if ! opkg install luci-app-ttyd >/dev/null 2>&1
then echo -e "\n${RED}–ě—ą–ł–Ī–ļ–į –Ņ—Ä–ł —É—Ā—ā–į–Ĺ–ĺ–≤–ļ–Ķ ttyd!${NC}\n"; PAUSE; return; fi; fi; echo -e "${CYAN}–Ě–į—Ā—ā—Ä–į–ł–≤–į–Ķ–ľ ${NC}ttyd"; sed -i 's#/bin/login#-t fontSize=15 sh /usr/bin/zms#' /etc/config/ttyd; /etc/init.d/ttyd restart >/dev/null 2>&1; if pidof ttyd >/dev/null
then echo -e "${GREEN}–°–Ľ—É–∂–Ī–į –∑–į–Ņ—É—Č–Ķ–Ĺ–į!${NC}\n\n${YELLOW}–Ē–ĺ—Ā—ā—É–Ņ –ł–∑ –Ī—Ä–į—É–∑–Ķ—Ä–į: ${NC}$LAN_IP:7681\n"; PAUSE; else echo -e "\n${RED}–ě—ą–ł–Ī–ļ–į! –°–Ľ—É–∂–Ī–į –Ĺ–Ķ –∑–į–Ņ—É—Č–Ķ–Ĺ–į!${NC}\n"; PAUSE; fi; fi; }
