while IFS= read -r line; do if echo "$line" | grep -q "^–ö–ĺ–Ĺ—ā—Ä–ĺ–Ľ—Ć–Ĺ—č–Ļ —ā–Ķ—Ā—ā"; then LEFT=$(echo "$line" | cut -d'‚Üí' -f1); RIGHT=$(echo "$line" | cut -d'‚Üí' -f2); RIGHT_CLEAN=$(echo "$RIGHT" | tr -cd '0-9/')
OK=$(echo "$RIGHT_CLEAN" | cut -d'/' -f1); TOTAL=$(echo "$RIGHT_CLEAN" | cut -d'/' -f2); [ -z "$OK" ] && OK=0; [ -z "$TOTAL" ] && TOTAL=0; if [ "$OK" -eq "$TOTAL" ] && [ "$TOTAL" -ne 0 ]; then COLOR="$GREEN"
