if echo "$line" | grep -q "\[ OK \]"; then echo -e "${GREEN}${line}${NC}"; elif echo "$line" | grep -q "\[FAIL\]"; then echo -e "${RED}${line}${NC}"; else echo "$line"; fi; done < "$FILE"; PAUSE; }
run_test_by_domain() { MODE="domain"; clear; echo -e "${MAGENTA}–Ę–Ķ—Ā—ā–ł—Ä–ĺ–≤–į–Ĺ–ł–Ķ —Ā—ā—Ä–į—ā–Ķ–≥–ł–Ļ –Ņ–ĺ –ī–ĺ–ľ–Ķ–Ĺ—É${NC}\n\n${CYAN}–í–≤–Ķ–ī–ł—ā–Ķ –ĺ–ī–ł–Ĺ –ł–Ľ–ł –Ĺ–Ķ—Ā–ļ–ĺ–Ľ—Ć–ļ–ĺ –ī–ĺ–ľ–Ķ–Ĺ–ĺ–≤ —á–Ķ—Ä–Ķ–∑ –Ņ—Ä–ĺ–Ī–Ķ–Ľ (–Ĺ–į–Ņ—Ä–ł–ľ–Ķ—Ä: ${NC}x.com vk.com${CYAN})${NC}\n"; echo -ne "${YELLOW}–í–≤–Ķ–ī–ł—ā–Ķ –ī–ĺ–ľ–Ķ–Ĺ: ${NC}"; read -r INPUT
