!skip {print}' "$CONF" > "${CONF}.tmp"; mv "${CONF}.tmp" "$CONF"; echo -e "\n${CYAN}–Ę–Ķ—Ā—ā–ł—Ä—É–Ķ–ľ —Ā—ā—Ä–į—ā–Ķ–≥–ł—é:${NC} ${YELLOW}${NAME}${NC} ($CUR/$TOTAL_STR)"; ZAPRET_RESTART; OK=0;
